def solve(well_type, depth, length=None):
    if well_type not in ['vertical', 'horizontal']:
        raise ValueError("Invalid well type. Must be 'vertical' or 'horizontal'.")

    if depth <= 0:
        raise ValueError("Depth must be a positive number.")

    if well_type == 'horizontal':
        if length is None or length <= 0:
            raise ValueError("Length must be provided and be a positive number for horizontal wells.")

    if well_type == 'vertical':
        return f"Drilling a vertical well to a depth of {depth} meters."

    if well_type == 'horizontal':
        return f"Drilling a horizontal well to a depth of {depth} meters and a length of {length} meters."
